#include <bits/stdc++.h>
using namespace std;
const int N=2e3+5;
int num[N];
int n,a[N],b[N],dp[N][N],ans=(1LL<<31)-1;
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		b[i]=a[i];
	}
	sort(b+1,b+n+1);
	int cnt=0;
	for(int i=1;i<=n;i++)
		if(i==1 || b[i]!=b[i-1])
			num[++cnt]=b[i];
	memset(dp,127,sizeof(dp));
	dp[0][1]=0;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=cnt;j++){
			//for(int k=1;k<=j;k++)
			//	dp[i][j]=min(dp[i][j],dp[i-1][k]+abs(a[i]-num[j]));
			dp[i][j]=min(dp[i][j-1]-abs(a[i]-num[j-1]),dp[i-1][j])+abs(a[i]-num[j]);
			if(i==n)
				ans=min(ans,dp[n][j]);
		}
	reverse(a+1,a+n+1);
	memset(dp,127,sizeof(dp));
	dp[0][1]=0;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=cnt;j++){
			//for(int k=1;k<=j;k++)
			//	dp[i][j]=min(dp[i][j],dp[i-1][k]+abs(a[i]-num[j]));
			dp[i][j]=min(dp[i][j-1]-abs(a[i]-num[j-1]),dp[i-1][j])+abs(a[i]-num[j]);
			if(i==n)
				ans=min(ans,dp[n][j]);
		}
	printf("%d\n",ans);
	return 0;
}
